	UPDATE TBL_VOLUN_APPLY
	SET VOLUNACT_APPLYSTATUS = 0,
    VOLUNACT_ATTENDANCE = #{volunActAttendance}
	WHERE VOLUN_ACT_NO = #{volunActNo}
 	AND USER_NO = #{userNo}
 	AND VOLUNACT_APPLYSTATUS = 1

mapper.select:
SELECT VOLUN_ACT_NO, VOLUN_ACT_TITLE, VOLUN_ACT_ACT_TYPE, TO_CHAR(VOLUN_ACT_RECRU_BEGIN, 'YYYY-MM-DD') AS VOLUN_ACT_RECRU_BEGIN, TO_CHAR(VOLUN_ACT_RECRU_END, 'YYYY-MM-DD') AS VOLUN_ACT_RECRU_END, CASE WHEN SYSDATE < VOLUN_ACT_RECRU_BEGIN THEN '모집예정' WHEN SYSDATE < VOLUN_ACT_RECRU_END + 1 THEN '모집중' ELSE '모집마감' END AS RECRU_STATUS FROM TBL_VOLUN_ACTIVITY WHERE VOLUN_ACT_ORGAN_NO = #{volunActOrganNo}
AND VOLUN_ACT_ACT_TYPE = #{actType}
AND ( (#{recruitStatus} = 'before-recruit' AND SYSDATE < VOLUN_ACT_RECRU_BEGIN) OR (#{recruitStatus} = 'recruit' AND SYSDATE >= VOLUN_ACT_RECRU_BEGIN AND SYSDATE < VOLUN_ACT_RECRU_END + 1) OR (#{recruitStatus} = 'recruit-end' AND SYSDATE >= VOLUN_ACT_RECRU_END + 1) )
AND VOLUN_ACT_TITLE LIKE '%' || #{keyword} || '%'
ORDER BY VOLUN_ACT_RECRU_END DESC

SELECT * FROM ( SELECT ROWNUM AS rn, T.* FROM ( SELECT VOLUN_ACT_NO, VOLUN_ACT_TITLE, VOLUN_ACT_ACT_TYPE, TO_CHAR(VOLUN_ACT_RECRU_BEGIN, 'YYYY-MM-DD') AS VOLUN_ACT_RECRU_BEGIN, TO_CHAR(VOLUN_ACT_RECRU_END, 'YYYY-MM-DD') AS VOLUN_ACT_RECRU_END, TO_CHAR(Volun_Act_Proc_Begin, 'YYYY-MM-DD') AS Volun_Act_Proc_Begin, TO_CHAR(Volun_Act_Proc_End, 'YYYY-MM-DD') AS Volun_Act_Proc_End, CASE WHEN SYSDATE < VOLUN_ACT_RECRU_BEGIN THEN '모집예정' WHEN SYSDATE < VOLUN_ACT_RECRU_END + 1 THEN '모집중' ELSE '모집마감' END AS RECRU_STATUS FROM TBL_VOLUN_ACTIVITY WHERE VOLUN_ACT_ORGAN_NO = #{volunActOrganNo}
AND VOLUN_ACT_ACT_TYPE = #{actType}
AND ( (#{recruitStatus} = 'before-recruit' AND SYSDATE < VOLUN_ACT_RECRU_BEGIN) OR (#{recruitStatus} = 'recruit' AND SYSDATE >= VOLUN_ACT_RECRU_BEGIN AND SYSDATE < VOLUN_ACT_RECRU_END + 1) OR (#{recruitStatus} = 'recruit-end' AND SYSDATE >= VOLUN_ACT_RECRU_END + 1) )
AND VOLUN_ACT_TITLE LIKE '%' || #{keyword} || '%'
ORDER BY CASE WHEN TRUNC(SYSDATE) < VOLUN_ACT_RECRU_BEGIN THEN 2 WHEN TRUNC(SYSDATE) <= VOLUN_ACT_RECRU_END THEN 1 ELSE 3 END, CASE WHEN TRUNC(SYSDATE) >= VOLUN_ACT_RECRU_BEGIN AND TRUNC(SYSDATE) <= VOLUN_ACT_RECRU_END THEN VOLUN_ACT_RECRU_END WHEN TRUNC(SYSDATE) < VOLUN_ACT_RECRU_BEGIN THEN VOLUN_ACT_RECRU_BEGIN END ASC, CASE WHEN TRUNC(SYSDATE) > VOLUN_ACT_RECRU_END THEN VOLUN_ACT_RECRU_END END DESC ) T WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

SELECT COUNT(VOLUN_ACT_NO)
FROM TBL_VOLUN_ACTIVITY
WHERE VOLUN_ACT_ORGAN_NO = #{volunActOrganNo}


